<?php declare(strict_types=1); ?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Beyond Green — Daily Breath adult wellness</title><meta name="description" content="Private adult cannabis wellness, education, tolerance and session tracking."><style>
:root{--bg:#06110b;--panel:#0d1f15;--line:#254b32;--green:#65df8e;--text:#f5fff7;--muted:#afd0b8;--warn:#ffd36a}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 80% 0,#1d6f4055,transparent 32%),var(--bg);color:var(--text);font:16px/1.55 Inter,system-ui,sans-serif}.shell{width:min(1160px,calc(100% - 32px));margin:auto}a{color:inherit}.nav{display:flex;align-items:center;justify-content:space-between;padding:16px max(18px,calc((100vw - 1160px)/2));border-bottom:1px solid var(--line);background:#06110be8;position:sticky;top:0;z-index:4}.brand{text-decoration:none;font-weight:1000}.pill{padding:8px 12px;border:1px solid #436c4d;border-radius:999px;font-size:12px}.hero{padding:82px 0 48px}.eyebrow{color:var(--green);font-size:12px;font-weight:1000;letter-spacing:.14em}.hero h1{font-size:clamp(50px,8vw,92px);line-height:.9;letter-spacing:-.06em;margin:12px 0 20px}.hero p{max-width:760px;color:var(--muted);font-size:19px}.notice{padding:16px 18px;border:1px solid #675b2b;border-radius:16px;background:#241e0b;color:#ffe7a2}.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:15px;padding:42px 0}.card{padding:22px;border:1px solid var(--line);border-radius:22px;background:linear-gradient(145deg,#102719,#0a1810)}.card span{font-size:30px}.card h2{font-size:20px;margin:10px 0 6px}.card p{margin:0;color:var(--muted)}.tracker{padding:28px;border:1px solid var(--line);border-radius:26px;background:#0b1b12;margin-bottom:55px}.tracker h2{margin-top:0}.fields{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.fields label{display:grid;gap:6px;color:var(--muted);font-size:13px}.fields input,.fields select,.fields textarea{width:100%;padding:13px;border:1px solid #315b3d;border-radius:12px;background:#07120c;color:#fff;font:inherit}.fields textarea{min-height:90px;resize:vertical}.wide{grid-column:1/-1}.btn{display:inline-flex;border:0;border-radius:12px;padding:13px 18px;background:linear-gradient(135deg,#50c878,#7ee9a1);color:#06200f;font-weight:1000;cursor:pointer;margin-top:14px}.status{margin-left:12px;color:var(--green)}.gate{position:fixed;inset:0;z-index:20;display:grid;place-items:center;padding:20px;background:rgba(1,7,3,.94)}.gate-box{max-width:520px;padding:30px;border:1px solid #39714a;border-radius:26px;background:#0c1d13;text-align:center}.gate h2{font-size:34px;margin:8px 0}.gate p{color:var(--muted)}.gate-actions{display:flex;gap:10px;justify-content:center;flex-wrap:wrap}.btn.secondary{background:#1b3323;color:#fff;border:1px solid #416b4c}.footer{padding:30px 0;border-top:1px solid var(--line);color:var(--muted)}@media(max-width:800px){.grid,.fields{grid-template-columns:1fr 1fr}}@media(max-width:550px){.grid,.fields{grid-template-columns:1fr}.hero{padding-top:55px}}
</style></head><body><div class="gate" id="gate"><div class="gate-box"><div style="font-size:46px">🌿</div><span class="eyebrow">ADULT WELLNESS</span><h2>Confirm your age</h2><p>Beyond Green contains cannabis-related wellness and educational content. You must meet the legal age in your location to continue.</p><div class="gate-actions"><button class="btn" id="enter">I meet the legal age</button><a class="btn secondary" href="/dailybreath/">Return to Daily Breath</a></div></div></div><header class="nav"><a class="brand" href="/dailybreath/">DAILY BREATH <span style="opacity:.6">/</span> BEYOND GREEN 🌿</a><span class="pill">Private · Adult-only</span></header><main class="shell"><section class="hero"><span class="eyebrow">CANNABIS-FRIENDLY · WELLNESS-FIRST</span><h1>Know your body.<br>Know your limits.</h1><p>Track sessions, tolerance, sleep, mood, appetite, pain, focus, hydration and personal goals—privately and without judgment.</p><div class="notice"><strong>Safety:</strong> Do not drive or operate machinery while impaired. Avoid mixing substances, wait before redosing, and store products securely away from children and pets.</div></section><section class="grid"><article class="card"><span>📝</span><h2>Session Journal</h2><p>Method, product, amount, mood before and after, effects, and duration.</p></article><article class="card"><span>⏱️</span><h2>Edible Timer</h2><p>Record start time and use a patient wait reminder before considering more.</p></article><article class="card"><span>📉</span><h2>Tolerance Tracker</h2><p>Frequency, spending, cravings, personal limits, and optional reset goals.</p></article><article class="card"><span>🌙</span><h2>Wellness Check-ins</h2><p>Compare cannabis use with sleep, anxiety, appetite, pain, focus, and exercise.</p></article><article class="card"><span>🧘</span><h2>T-break Plans</h2><p>Structured 3, 7, 14, and 30-day breaks with reflection and coping prompts.</p></article><article class="card"><span>🔒</span><h2>Private Mode</h2><p>Local-first notes now, with Beyond ID PIN protection planned for synced records.</p></article></section><section class="tracker"><span class="eyebrow">PRIVATE LOCAL JOURNAL</span><h2>Quick session check-in</h2><div class="fields"><label>Date & time<input id="dt" type="datetime-local"></label><label>Method<select id="method"><option>Flower</option><option>Vaporizer</option><option>Edible</option><option>Oil / tincture</option><option>Topical</option><option>Other</option></select></label><label>THC / CBD<input id="ratio" placeholder="Example: 10 mg THC / 10 mg CBD"></label><label>Mood before<input id="before" placeholder="Calm, anxious, tired…"></label><label>Mood after<input id="after" placeholder="Relaxed, focused, sleepy…"></label><label>Amount<input id="amount" placeholder="Use the product label"></label><label class="wide">Notes<textarea id="notes" placeholder="Effects, duration, hydration, appetite, unwanted effects…"></textarea></label></div><button class="btn" id="save">Save privately on this device</button><span class="status" id="status"></span></section></main><footer class="footer"><div class="shell">Educational tracking only. Not medical advice or a substitute for professional care.</div></footer><script>
const gate=document.getElementById('gate');if(localStorage.getItem('beyondGreenAdult')==='yes')gate.style.display='none';document.getElementById('enter').onclick=()=>{localStorage.setItem('beyondGreenAdult','yes');gate.style.display='none'};document.getElementById('dt').value=new Date(Date.now()-new Date().getTimezoneOffset()*60000).toISOString().slice(0,16);document.getElementById('save').onclick=()=>{const record={date:dt.value,method:method.value,ratio:ratio.value,before:before.value,after:after.value,amount:amount.value,notes:notes.value};const rows=JSON.parse(localStorage.getItem('beyondGreenSessions')||'[]');rows.unshift(record);localStorage.setItem('beyondGreenSessions',JSON.stringify(rows.slice(0,100)));status.textContent='Saved on this device ✓';};
</script></body></html>